#include<bits/stdc++.h>
using namespace std;
long long t;
int n,a[100010],p[100010];
int main()
{
    scanf("%lld%d",&t,&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        p[a[i]]=i;
    }
    if(t%2==1)
    {
        for(int i=1;i<=n;i++)
        {
            if(i!=a[i])
            {
                swap(a[i],a[p[i]]);
                break;
            }
        }
        for(int i=1;i<=n;i++)
        {
            printf("%d ",a[i]);
        }
        return 0;
    }
    if(t%2==0)
    {
        if(a[1]==n)
        {
            for(int i=1;i<=n;i++)
            {
                printf("%d ",a[i]);
            }
            return 0;
        }
        if(a[1]==1&&a[2]==n)
        {
            for(int i=3;i<=n;i++)
            {
                if(a[i]!=i-1)
                {
                    swap(a[i],a[p[i-1]]);
                    break;
                }
            }
            swap(a[1],a[2]);
            for(int i=1;i<=n;i++)
            {
                printf("%d ",a[i]);
            }
            return 0;
        }
        for(int i=2;i<=n;i++)
        {
            if(a[i]!=i-1)
            {
                swap(a[i],a[p[i-1]]);
                break;
            }
        }
        swap(a[1],a[p[n]]);
        for(int i=1;i<=n;i++)
        {
            printf("%d ",a[i]);
        }
        return 0;
    }
    return 0;
}
